98	/// Transfers `narg` arguments from `state` to `co`, resumes the coroutine,
99	/// then transfers results (or error message) back to `state`.
100	///
101	/// Returns the number of result values (≥ 0) on success, or `-1` on error
102	/// with the error object left on top of `state`'s stack.
103	///
104	/// C: `static int auxresume(lua_State *L, lua_State *co, int narg)`
105	fn aux_resume(state: &mut LuaState, _co: GcRef<lua_types::value::LuaThread>, _narg: i32) -> i32 {
106	    // TODO(port): coroutine stub — the complete body requires all of:
107	    //
108	    //   1. if !lua_checkstack(co, narg) { push "too many arguments"; return -1; }
109	    //      → co.ensure_stack(narg) — grow co's stack for the incoming arguments.
110	    //
111	    //   2. lua_xmove(L, co, narg)
112	    //      → state.xmove(&co, narg) — transfer narg values from L's stack to co's.
113	    //
114	    //   3. status = lua_resume(co, L, narg, &nres)
115	    //      → co.resume(state, narg) — execute co until it yields, returns, or errors.
116	    //        Returns (LuaStatus, nres: i32).
117	    //
118	    //   4. On LUA_OK / LUA_YIELD success path:
119	    //      if !lua_checkstack(L, nres + 1) { lua_pop(co, nres); push "too many results"; return -1; }
120	    //      lua_xmove(co, L, nres) — move results back.
121	    //      return nres;
122	    //
123	    //   5. On error path:
124	    //      lua_xmove(co, L, 1) — move error message back.
125	    //      return -1;
126	    //
127	    // All cross-thread operations depend on Phase E / corosensei runtime support.
128	    let _ = state;
129	    todo!(
130	        "phase-e: coroutine_resume — stackful coroutines need corosensei (PORTING.md §2 #6)"
131	    );
132	}
