163	/// Closure body installed by `coroutine.wrap`.  The wrapped coroutine is
164	/// stored in upvalue slot 1.
165	///
166	/// On error the message is augmented with location info (if a string), then
167	/// re-raised.  If the coroutine is in an error state (not simply suspended),
168	/// its to-be-closed variables are cleaned up before propagation.
169	///
170	/// C: `static int luaB_auxwrap(lua_State *L)`
171	fn aux_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
172	    // C: lua_State *co = lua_tothread(L, lua_upvalueindex(1));
173	    // TODO(port): coroutine stub — upvalue_index(1) gives the first C-closure
174	    // upvalue pseudo-index; to_thread reads GcRef<LuaState> from that slot.
175	    let co = match state.to_thread(upvalue_index(1)) {
176	        Some(c) => c,
177	        None => panic!("coroutine.wrap: upvalue 1 is not a thread (Phase A–D stub)"),
178	    };
179	    // C: int r = auxresume(L, co, lua_gettop(L));
180	    let narg = state.get_top();
181	    let r = aux_resume(state, co.clone(), narg);
182	    let _ = co;
183	    if r < 0 {
184	        // TODO(phase-b): needs cross-thread status, close_thread, xmove.
185	        todo!("phase-b: coroutine wrap error path")
186	    } else {
187	        Ok(r as usize)
188	    }
189	}
