191	/// `coroutine.create(f)` — create a new coroutine that will run function `f`.
192	///
193	/// Pushes the new thread value and returns 1.
194	///
195	/// C: `static int luaB_cocreate(lua_State *L)`
196	pub fn co_create(state: &mut LuaState) -> Result<usize, LuaError> {
197	    // C: luaL_checktype(L, 1, LUA_TFUNCTION);
198	    state.check_arg_type(1, LuaType::Function)?;
199	    // C: NL = lua_newthread(L);
200	    // TODO(port): coroutine stub — new_thread allocates a fresh LuaState coroutine
201	    // and pushes a Thread value for it; Phase E needed.
202	    let _nl = state.new_thread()?;
203	    // C: lua_pushvalue(L, 1);          /* move function to top */
204	    // C: lua_xmove(L, NL, 1);          /* move function from L to NL */
205	    // PORT NOTE: in C the function copy is pushed and then xmove pops it
206	    // off L's stack into NL's. The Phase E xmove is not yet wired, but the
207	    // net stack effect on L is "thread on top". Skip the push entirely so
208	    // co_wrap's push_cclosure captures the thread (not the function) as
209	    // upvalue 1. Phase E will restore the push + xmove pair.
210	    // TODO(port): coroutine stub — xmove transfers the function from L's stack to
211	    // NL's stack so it becomes the coroutine body; Phase E needed.
212	    Ok(1)
213	}
214	
215	/// `coroutine.wrap(f)` — create a coroutine and return a resuming function.
216	///
217	/// The returned function, when called, resumes the coroutine as if by
218	/// `coroutine.resume`, but raises an error rather than returning `false`.
219	///
220	/// C: `static int luaB_cowrap(lua_State *L)`
221	pub fn co_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
222	    // C: luaB_cocreate(L);
223	    co_create(state)?;
224	    // C: lua_pushcclosure(L, luaB_auxwrap, 1);
225	    // TODO(port): push_cclosure(aux_wrap, 1) creates a C closure with the thread
226	    // (currently on top of the stack) as upvalue 1; Phase B wire-up needed.
227	    state.push_cclosure(aux_wrap, 1)?;
228	    Ok(1)
229	}
