231	/// `coroutine.yield([...])` — suspend the running coroutine.
232	///
233	/// All arguments are passed back as results of the corresponding `resume`.
234	///
235	/// C: `static int luaB_yield(lua_State *L)`
236	pub fn co_yield(state: &mut LuaState) -> Result<usize, LuaError> {
237	    // C: return lua_yield(L, lua_gettop(L));
238	    // TODO(port): coroutine stub — state.yield_(n) suspends the coroutine and
239	    // transfers n values back to the caller of resume; Phase E needed.
240	    let _nargs = state.get_top();
241	    todo!(
242	        "phase-e: coroutine_yield — stackful coroutines need corosensei (PORTING.md §2 #6)"
243	    );
244	}
