246	/// `coroutine.status(co)` — return a string describing `co`'s current status.
247	///
248	/// Returns one of `"running"`, `"dead"`, `"suspended"`, or `"normal"`.
249	///
250	/// C: `static int luaB_costatus(lua_State *L)`
251	pub fn co_status(state: &mut LuaState) -> Result<usize, LuaError> {
252	    // C: lua_State *co = getco(L);
253	    let co = get_co(state)?;
254	    // C: lua_pushstring(L, statname[auxstatus(L, co)]);
255	    let idx = aux_status(state, &co) as usize;
256	    let name: &[u8] = STAT_NAMES[idx];
257	    let interned = state.intern_str(name)?;
258	    state.push(LuaValue::Str(interned));
259	    Ok(1)
260	}
261	
262	/// `coroutine.isyieldable([co])` — test whether a coroutine (default: current)
263	/// is in a yieldable state.
264	///
265	/// C: `static int luaB_yieldable(lua_State *L)`
266	pub fn co_isyieldable(state: &mut LuaState) -> Result<usize, LuaError> {
267	    let is_yieldable = if matches!(state.type_at(1), LuaType::None) {
268	        state.is_yieldable()
269	    } else {
270	        let _co = get_co(state)?;
271	        // TODO(phase-b): needs cross-thread is_yieldable; Phase E.
272	        todo!("phase-b: cross-thread is_yieldable")
273	    };
274	    state.push(LuaValue::Bool(is_yieldable));
275	    Ok(1)
276	}
277	
278	/// `coroutine.running()` — return the current coroutine plus a boolean.
279	///
280	/// The boolean is `true` when the current coroutine is the main thread.
281	///
282	/// C: `static int luaB_corunning(lua_State *L)`
283	pub fn co_running(state: &mut LuaState) -> Result<usize, LuaError> {
284	    // C: int ismain = lua_pushthread(L);
285	    // TODO(port): push_thread pushes a Thread value for the current LuaState and
286	    // returns true iff it is the main thread; Phase B wire-up needed.
287	    let is_main = state.push_thread()?;
288	    // C: lua_pushboolean(L, ismain);
289	    state.push(LuaValue::Bool(is_main));
290	    Ok(2)
291	}
292	
293	/// `coroutine.close(co)` — close a dead or suspended coroutine.
294	///
295	/// Runs the to-be-closed variable finalizers.  Returns `true` on success, or
296	/// `false` plus an error object on failure.  Raises an error if `co` is
297	/// running or normal.
298	///
299	/// C: `static int luaB_close(lua_State *L)`
300	pub fn co_close(state: &mut LuaState) -> Result<usize, LuaError> {
301	    let co = get_co(state)?;
302	    let status = aux_status(state, &co);
303	    match status {
304	        s if s == COS_DEAD || s == COS_YIELD => {
305	            // TODO(phase-b): needs cross-thread close_thread + xmove.
306	            todo!("phase-b: coroutine close")
307	        }
308	        _ => {
309	            let name = match status {
310	                COS_RUN => "running",
311	                COS_NORM => "normal",
312	                _ => "unknown",
313	            };
314	            Err(LuaError::runtime(format_args!(
315	                "cannot close a {} coroutine",
316	                name
317	            )))
318	        }
319	    }
320	}
321	
322	// ── Module entry point ────────────────────────────────────────────────────────
323	
324	/// Opens the `coroutine` standard library by pushing a new table containing
325	/// all `coroutine.*` functions.
326	///
327	/// C: `LUAMOD_API int luaopen_coroutine(lua_State *L)` — `LUAMOD_API` → `pub`.
328	pub fn open_coroutine(state: &mut LuaState) -> Result<usize, LuaError> {
329	    // C: luaL_newlib(L, co_funcs);
330	    // TODO(port): state.new_lib(CO_FUNCS) creates a table from the registration
331	    // slice and leaves it on the stack; Phase B wire-up needed.
332	    state.new_lib(CO_FUNCS)?;
333	    Ok(1)
334	}
